from dataclasses import dataclass
from typing import List, Dict

@dataclass
class TeamUsageSnapshot:
    team_id: str
    model_id: str
    monthly_input_tokens: int
    monthly_output_tokens: int
    monthly_cache_tokens: int

@dataclass
class RateChangeImpact:
    team_id: str
    model_id: str
    old_monthly_cost: float
    new_monthly_cost: float

    @property
    def delta_usd(self) -> float:
        return self.new_monthly_cost - self.old_monthly_cost

    @property
    def delta_pct(self) -> float:
        if self.old_monthly_cost == 0:
            return 0.0
        return self.delta_pct_raw

    @property
    def delta_pct_raw(self) -> float:
        return (self.new_monthly_cost - self.old_monthly_cost) / self.old_monthly_cost * 100

def compute_impact(
    snapshots: List[TeamUsageSnapshot],
    old_rates: Dict[str, Dict[str, float]],   # model_id → {input, output, cache}
    new_rates: Dict[str, Dict[str, float]],
) -> List[RateChangeImpact]:
    impacts = []
    for snap in snapshots:
        if snap.model_id not in old_rates:
            continue
        old_r = old_rates[snap.model_id]
        new_r = new_rates[snap.model_id]

        def cost(rates):
            return (snap.monthly_input_tokens / 1e6 * rates["input"]
                    + snap.monthly_output_tokens / 1e6 * rates["output"]
                    + snap.monthly_cache_tokens / 1e6 * rates.get("cache", 0))

        impacts.append(RateChangeImpact(
            team_id=snap.team_id,
            model_id=snap.model_id,
            old_monthly_cost=cost(old_r),
            new_monthly_cost=cost(new_r),
        ))
    return sorted(impacts, key=lambda x: abs(x.delta_usd), reverse=True)
